  const options: SetupOptions = {
    provider: presetProvider,
    force: false,
    noGitConfig: false,
    noBrowser: false,
    noClipboard: false,
  };

  for (let index = 0; index < argv.length; index += 1) {
    const token = argv[index];

    switch (token) {
      case "-e":
      case "--email":
        options.email = requireValue(token, argv[index + 1]);
        index += 1;
        break;
      case "-k":
      case "--key":
        options.key = requireValue(token, argv[index + 1]);
        index += 1;
        break;
      case "-p":
      case "--provider":
        options.provider = normalizeNamedProvider(requireValue(token, argv[index + 1]));
        index += 1;
        break;
      case "-H":
      case "--host":
        options.host = requireValue(token, argv[index + 1]);
        index += 1;
        break;
      case "--force":
        options.force = true;
        break;
      case "--no-git-config":
        options.noGitConfig = true;
        break;
      case "--no-browser":
        options.noBrowser = true;
        break;
      case "--no-clipboard":
        options.noClipboard = true;
        break;
      case "-h":
      case "--help":
        throw new Error(getHelpText());
      default:
        if (token.startsWith("-")) {
          throw new Error(`Unknown flag: ${token}`);
        }

        if (!options.provider) {
          options.provider = normalizeNamedProvider(token);
          break;
        }

        throw new Error(`Unexpected argument: ${token}`);
    }
  }

  return options;
}

