      {screen === "key-list" && <KeyList onBack={goBack} />}
      {screen === "test-connection" && <TestConnection onBack={goBack} />}
      {screen === "agent" && <Agent onBack={goBack} />}
    </Box>
  )
}

export function App(): React.ReactNode {
