      )}

      {agentKeys.map((k, i) => (
        <ListItem
          key={k.fingerprint}
          isFocused={i === selectedIndex}
          isSelected={i === selectedIndex}
          description={k.type}
        >
          {k.path.split("/").pop() ?? k.path}
        </ListItem>
      ))}

      {(status || error) && (
        <Box marginTop={1}>
          {status && <Text dimColor>{status}</Text>}
          {error && <Text color="red">{error}</Text>}
        </Box>
      )}

      <Box marginTop={1}>
        <Text dimColor>↑↓ navigate · a add key · d remove key · Esc back</Text>
      </Box>
    </Box>
